// Sort descending by salary

exercises.expected_solution:
import java.util.Arrays;

class Employee implements Comparable<Employee> {
    private String name;
    private double salary;

    public Employee(String name, double salary) {
        this.name = name;
        this.salary = salary;
    }

    public String getName() { return name; }
    public double getSalary() { return salary; }

    @Override
    public int compareTo(Employee other) {
        // Descending: compare other to this (reversed)
        return Double.compare(other.salary, this.salary);
    }

    @Override
    public String toString() {
        return name + ": ₹" + salary;
    }
}

public class App {
    public static void main(String[] args) {
        Employee[] staff = {
            new Employee("Priya", 72000),
            new Employee("Aisha", 95000),
            new Employee("Vikram", 68000),
            new Employee("Raj", 85000)
        };
        Arrays.sort(staff);
        for (Employee e : staff) System.out.println(e);
    }
}

