import java.util.Arrays;

interface Summarizable {
    String summary();
    default void printSummary() { System.out.println(summary()); }
}

interface Scorable {
    int getScore();
}

class Student implements Comparable<Student>, Summarizable, Scorable {
    private String name;
    private int score;

    public Student(String name, int score) {
        this.name = name;
        this.score = score;
    }

    @Override public int getScore() { return score; }

    @Override public String summary() { return name + ": " + score; }

    @Override
    public int compareTo(Student other) {
        return Integer.compare(other.score, this.score); // descending
    }
}

public class App {
    public static void main(String[] args) {
        Student[] students = {
            new Student("Priya", 78),
            new Student("Aisha", 92),
            new Student("Raj", 87)
        };
        Arrays.sort(students);
        for (Student s : students) s.printSummary();
    }
}

