// OnlineProduct, StoreProduct implement it
// printBestDeal accepts Discountable[]

exercises.expected_solution:
interface Discountable {
    String getName();
    double getPrice();
    double getDiscountPercent();

    default double discountedPrice() {
        return getPrice() * (1 - getDiscountPercent() / 100);
    }
}

class OnlineProduct implements Discountable {
    private String name;
    private double price;
    private double discount;

    public OnlineProduct(String name, double price, double discount) {
        this.name = name; this.price = price; this.discount = discount;
    }

    @Override public String getName() { return name; }
    @Override public double getPrice() { return price; }
    @Override public double getDiscountPercent() { return discount; }
}

class StoreProduct implements Discountable {
    private String name;
    private double price;
    private double discount;

    public StoreProduct(String name, double price, double discount) {
        this.name = name; this.price = price; this.discount = discount;
    }

    @Override public String getName() { return name; }
    @Override public double getPrice() { return price; }
    @Override public double getDiscountPercent() { return discount; }
}

public class App {
    static void printBestDeal(Discountable[] items) {
        Discountable best = items[0];
        for (Discountable d : items) {
            if (d.discountedPrice() < best.discountedPrice()) best = d;
        }
        System.out.printf("Best deal: %s at ₹%.2f%n", best.getName(), best.discountedPrice());
    }

    public static void main(String[] args) {
        Discountable[] items = {
            new OnlineProduct("Keyboard", 1999, 15),   // 1999 * 0.85 = 1699.15
            new StoreProduct("Mouse", 599, 10),          // 599 * 0.90 = 539.10
            new OnlineProduct("USB Hub", 499, 25)        // 499 * 0.75 = 374.25
        };
        printBestDeal(items);
    }
}

