import java.util.Arrays;

// GameEntry with tie-break compareTo
// Print with rank after sort

exercises.expected_solution:
import java.util.Arrays;

class GameEntry implements Comparable<GameEntry> {
    private String playerName;
    private int score;
    private int level;

    public GameEntry(String playerName, int score, int level) {
        this.playerName = playerName;
        this.score = score;
        this.level = level;
    }

    @Override
    public int compareTo(GameEntry other) {
        // Primary: score descending
        int cmp = Integer.compare(other.score, this.score);
        if (cmp != 0) return cmp;
        // Tie-break: level descending
        return Integer.compare(other.level, this.level);
    }

    public String formatWithRank(int rank) {
        return "#" + rank + " " + playerName + " — " + score + " pts (lvl " + level + ")";
    }
}

public class App {
    public static void main(String[] args) {
        GameEntry[] board = {
            new GameEntry("Priya", 8200, 7),
            new GameEntry("Aisha", 9500, 8),
            new GameEntry("Anita", 7800, 4),
            new GameEntry("Raj", 9500, 6),
            new GameEntry("Vikram", 7800, 5)
        };
        Arrays.sort(board);
        for (int i = 0; i < board.length; i++) {
            System.out.println(board[i].formatWithRank(i + 1));
        }
    }
}

interface Validator<T> {
    boolean validate(T value);
    String errorMessage();

    default void check(T value) {
        if (validate(value)) {
            System.out.println("Validating '" + value + "': OK");
        } else {
            System.out.println("Validating '" + value + "': [ERROR] " + errorMessage());
        }
    }
}

class LengthValidator implements Validator<String> {
    private int minLength;

    public LengthValidator(int minLength) { this.minLength = minLength; }

    @Override public boolean validate(String value) { return value.length() >= minLength; }
    @Override public String errorMessage() { return "String must be at least " + minLength + " characters"; }
}

class RangeValidator implements Validator<Integer> {
    private int min, max;

    public RangeValidator(int min, int max) { this.min = min; this.max = max; }

    @Override public boolean validate(Integer value) { return value >= min && value <= max; }
    @Override public String errorMessage() { return "Value must be between " + min + " and " + max; }
}

public class App {
    public static void main(String[] args) {
        LengthValidator lv = new LengthValidator(5);
        lv.check("hi");
        lv.check("hello");

        RangeValidator rv = new RangeValidator(10, 100);
        rv.check(3);
        rv.check(50);
    }
}

