import java.util.Arrays;

// Interfaces: Categorizable, Discountable
// Product implements Comparable, Categorizable, Discountable
// Utility method: printElectronics(Categorizable[])

exercises.expected_solution:
import java.util.Arrays;

interface Categorizable {
    String category();
    default boolean isElectronics() { return "Electronics".equals(category()); }
}

interface Discountable {
    String getName();
    double getPrice();
    double getDiscount();
    default double finalPrice() { return getPrice() * (1 - getDiscount() / 100); }
}

class Product implements Comparable<Product>, Categorizable, Discountable {
    private String name;
    private String cat;
    private double price;
    private double discount;

    public Product(String name, String cat, double price, double discount) {
        this.name = name; this.cat = cat; this.price = price; this.discount = discount;
    }

    @Override public String getName() { return name; }
    @Override public String category() { return cat; }
    @Override public double getPrice() { return price; }
    @Override public double getDiscount() { return discount; }

    @Override
    public int compareTo(Product other) {
        return Double.compare(this.finalPrice(), other.finalPrice());
    }

    @Override
    public String toString() {
        return String.format("%s: ₹%.2f (%s)", name, finalPrice(), cat);
    }
}

public class App {
    static void printElectronics(Categorizable[] items) {
        System.out.println("--- Electronics only ---");
        for (Categorizable c : items) {
            if (c.isElectronics()) System.out.println(((Discountable)c).getName());
        }
    }

    public static void main(String[] args) {
        Product[] catalog = {
            new Product("Keyboard", "Electronics", 1999, 15),
            new Product("Mouse", "Electronics", 599, 10),
            new Product("Java Book", "Books", 599, 15),
            new Product("USB Hub", "Electronics", 499, 25)
        };

        Arrays.sort(catalog);
        System.out.println("--- Sorted by final price ---");
        for (Product p : catalog) System.out.println(p);

        System.out.println();
        printElectronics(catalog);
    }
}
